// components/particles/LogisticsParticles.jsx
import { useEffect, useState } from "react";
import Particles, { initParticlesEngine } from "@tsparticles/react";
import { loadSlim } from "tsparticles-slim";

export default function LogisticsParticles() {
  const [init, setInit] = useState(false);

  useEffect(() => {
    initParticlesEngine(async (engine) => {
      await loadSlim(engine);
    }).then(() => {
      setInit(true);
    });
  }, []);

  const options = {
    fullScreen: {
      enable: false, // важно: false, чтобы canvas лежал внутри .auth-page
    },

    background: {
      color: "transparent",
    },

    fpsLimit: 60,

    particles: {
      number: {
        value: 80,
        density: { enable: true, area: 900 },
      },

      color: {
        value: ["#7ddf64", "#34d399", "#6ee7b7", "#ffffff"],
      },

      shape: {
        // Смешиваем круги (машины) и линии (дороги/лучи)
        type: ["circle"],
      },

      opacity: {
        value: { min: 0.3, max: 0.85 },
        animation: {
          enable: true,
          speed: 0.6,
          sync: false,
        },
      },

      size: {
        value: { min: 2, max: 7 },
        animation: {
          enable: true,
          speed: 2,
          sync: false,
        },
      },

      // Связи — это "дороги" между частицами
      links: {
        enable: true,
        distance: 180,
        color: "#7ddf64",
        opacity: 0.25,
        width: 1.5,
        // Треугольные связи — создают ощущение сети маршрутов
        triangles: {
          enable: true,
          color: "#b8f7a7",
          opacity: 0.06,
        },
      },

      move: {
        enable: true,
        speed: { min: 1, max: 3.5 },
        direction: "none",
        random: true,
        straight: false,
        outModes: { default: "out" },
        attract: {
          enable: true,
          rotate: { x: 600, y: 1200 },
        },
      },

      // Эффект "лучей" — длинные хвосты у быстрых частиц
      trail: {
        enable: true,
        length: 8,
        fillColor: "transparent",
      },
    },

    interactivity: {
      events: {
        onHover: {
          enable: true,
          mode: ["grab", "bubble"],
        },
        onClick: {
          enable: true,
          mode: "push",
        },
      },
      modes: {
        grab: {
          distance: 160,
          links: { opacity: 0.6 },
        },
        bubble: {
          distance: 120,
          size: 10,
          duration: 0.4,
          opacity: 0.9,
        },
        push: {
          quantity: 3,
        },
      },
    },

    detectRetina: true,
  };

  if (!init) return null;

  return (
    <Particles
      id="logistics-particles"
      options={options}
      style={{
        position: "absolute",
        inset: 0,
        width: "100%",
        height: "100%",
        zIndex: 0,
      }}
    />
  );
}
